var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"제기랄, 이 망할 침식체 자식들…! 끝도 없이 몰려오잖아……!!","JPN":"クソ、この忌々しい侵食体どもめ……！　キリがない……！！","ENG":"Damn it, these stupid C.O.s...! They just keep coming...!!","TWN":"該死，這些該死的侵蝕體！真是無窮無盡……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L5_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"꼬맹이! 그 망원경인가 뭔가는 아직 멀었어?","JPN":"おい、おこちゃま！　望遠鏡とやらはまだなのか？","ENG":"Kid! How much longer for that Telescope or whatever?!","TWN":"小鬼！那個望遠鏡還沒準備好嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이러다간 누구 하나 송장 치게 생겼다고……!","JPN":"このままじゃ、足腰無事には帰れないって……！","ENG":"At this rate, someone's gonna end up in a body bag...!","TWN":"這樣下去，恐怕會有人送命！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"라이카, 이제 대충 감 잡았어요!","JPN":"ライカ、大体わかってきたわ！","ENG":"Laika, I think I've finally got a handle on it!","TWN":"萊卡，我現在大概明白了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"메이시 박사님은 망원경이 원래 무기가 아니라고 했지만…….","JPN":"メイシ博士は望遠鏡が本来、武器ではないと言っていたけど……","ENG":"Dr. Macy said the Telescope wasn't originally designed as a weapon, but...","TWN":"雖然梅西博士說望遠鏡本來不是武器……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"지금껏 망원 렌즈만 써왔던 제 입장에서는 오히려 이쪽이 훨씬 안정적이에요!","JPN":"今までずっと望遠レンズばかり使ってきた私からすれば、こっちの方が何倍も安定している！","ENG":"For someone like me who's always used the Zoom Lens, this actually feels way more stable!","TWN":"從我長時間使用望遠鏡頭的立場來看，反而這邊更加穩定！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이거 어쩌면 정말로……!","JPN":"これならいけるかも……！","ENG":"This might really work...!","TWN":"這可能真的！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"다들 지금부터 잘 들어요……!","JPN":"みなさん、よく聞いてください……！","ENG":"Everyone, listen up...!","TWN":"大家從現在開始聽好了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이 망원경의 최대 출력이라면, 저기 있는 허신을 땅으로 떨어트릴 수 있어요!","JPN":"この望遠鏡の最大出力があれば、あの虚神を地に落とすことができます！","ENG":"At full power, this Telescope should be able to knock that Hollow God out of the sky!","TWN":"如果是這台望遠鏡的最大輸出功率的話，我可以把那邊的虛神從天上打下來！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 그게 정말이야?","JPN":"え？　本当？","ENG":"What? Are you serious?!","TWN":"什麼？那是真的嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"하지만 그렇게 오래 묶어 둘 수는 없을 거예요! 아마도 3초 정도……!","JPN":"でも、そう長くはもちません！　おそらく3秒が限界……！","ENG":"But I won't be able to hold it down for long! Maybe three seconds... tops!","TWN":"但是不能把它綁太久！大概3秒左右……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그 뒤에는 과열된 동력원을 교체할 시간이 필요해요!","JPN":"その後はオーバーヒートした動力源を交換する時間が必要です！","ENG":"After that, I'll need time to swap out the overheated power source!","TWN":"之後需要時間更換過熱的動力源！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"겨우 3초라고……?","JPN":"3秒だって……？","ENG":"Only three seconds...?","TWN":"才3秒嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"거, 꼬맹이가 더럽게 빡빡하게 구네! 낭낭하게 2초만 더 달라고……!","JPN":"いくらなんでも短すぎる！　もう2秒くらい何とかできない！？","ENG":"Kid, you're killing me here! Can't you pad it out to five?!","TWN":"哎，小鬼真是頑固！再多給我2秒鐘嘛……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"어이, 형씨! 꼬맹이랑 흥정해서 뭐 하게? 투덜대지 말라고!","JPN":"おい、そこ！　おこちゃま相手に欲張り過ぎだ！　文句言うな！","ENG":"Hey, pal! What good's haggling gonna do?! Quit whining!","TWN":"哎，大哥！跟小鬼討價還價做什麼？別抱怨了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L29_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"애초에 꼬맹이 없었으면, 저 6종 침식체를 떨어트릴 방법 자체가 없는 거 아니야?","JPN":"そもそもあいつがいなければ、あの第6種侵食体を落とす方法自体がなかったんだからな！","ENG":"Without the kid, we wouldn't even have a way to bring down that damn Category 6 C.O. in the first place!","TWN":"如果沒有那個小鬼，我們根本沒有辦法擊退那個6類侵蝕體吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"하핫! 이쪽 메이드 언니, 성격 화끈해서 마음에 드는데?","JPN":"ははっ！　そっちのメイドさん、言ってくれるね！　気に入った！","ENG":"Haha! I like you, maid girl. You've got fire.","TWN":"哈哈！這位女僕姊姊，性格火辣，我喜歡！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"쳇, 메이드 아니라니깐!","JPN":"ちっ、だからメイドじゃないっての！","ENG":"Tch, I'm not a maid!","TWN":"嘖，我說了不是女僕！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"지상으로 추락한 거짓된 신의 육체를 파괴하여 움직임을 멎게 하는 것도 중요한 일이나.","JPN":"地上に墜落した偽りの神の肉体を破壊し、動きを止めるのも重要なことではあるが。","ENG":"Crashing the body of a Hollow God to earth and halting its rampage is important.","TWN":"摧毀墜落到地面的虛神的軀體，阻止其行動也是一件重要的事。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_BIG"},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"허신은 불사의 존재. 저 추악한 것에게 안식을 선사하는 것 또한 더욱 중요한 일일지니.","JPN":"虚神は不死の存在。あの醜悪なものに安息を授けることはさらに重要なことと言えよう。","ENG":"But a Hollow God is an immortal being. Offering peace to that hideous being is an even greater duty.","TWN":"虛神是不滅的存在，讓那醜陋之物安息也是更為重要的事情。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그대여, 그것은 오로지 신을 죽이는 검을 가진 그대의 소임이다.","JPN":"それはただ一人、神を殺す剣を持つそなたにしか果たせない役目である。","ENG":"And that duty falls only to you, who wields the Godslayer.","TWN":"那是持有殺神之劍的你唯一的使命。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알고 있어……!","JPN":"わかってる……！","ENG":"I know...!","TWN":"我知道！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트가 허신을 떨어트리면, 다른 사람들이 허신의 움직임을 최대한 봉쇄하고…….","JPN":"フェリセットが虚神を落としてくれたら、他のみんなでできる限り動きを止めて……","ENG":"When Félicette makes the Hollow God fall, everyone else should hold it down...","TWN":"費莉塞特擊落虛神後，其他人儘量封鎖虛神的行動……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 사이에 내가 허신의 심장을 파괴하면 되는 거지?","JPN":"その隙に私が虚神の心臓を破壊すればいいんだよね？","ENG":"And I should go in for the kill by destroying the heart, right?","TWN":"在這期間，我只需要摧毀虛神的心臟就行了吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좋아, 한 번 해보자고……!","JPN":"いいよ、やってみよう……！","ENG":"All right, let's do this...!","TWN":"好，那就試試看！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"어쩌면 두 번 다시 기회가 없을지도 몰라요!","JPN":"もしかしたら、チャンスは一度きりかもしれません！","ENG":"We might not get another shot at this!","TWN":"也許我們只有這一次機會！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"다들 최대한 타이밍을 맞춰서 한 번에 가는 거예요……!","JPN":"みなさん、できるだけタイミングを合わせて、一気に畳みかけてください……！","ENG":"Everyone, the time is just right. We only get one chance...!","TWN":"大家把握好時機，爭取一舉拿下！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"벡터 변환 최대치! 그래비티 건 레디……!","JPN":"ベクター変換最大！　グラビティガン、レディー……！","ENG":"Vector conversion at max! Gravity gun ready...!","TWN":"向量轉換最大值！準備……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"발사……!!","JPN":"発射……！！","ENG":"Firing...!!","TWN":"發射……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"정말 허신을 떨어트렸잖아? 위력이 끝장 나는데……!?","JPN":"本当に虚神を落とした？　どんな威力だよ……！？","ENG":"You really dropped it?! That's some insane firepower...!","TWN":"真的把虛神打下來了？威力真是驚人……！？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"전장에서 방심은 가장 큰 죄악이고 기회는 다시 오지 않으니.","JPN":"戦場での油断こそ最大の罪、機会は二度訪れぬ。","ENG":"There is no greater sin on the battlefield than letting your guard down, and chances like this never come twice.","TWN":"在戰場上，疏忽是最大的罪惡，機會只有一次。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"필히 지상으로 추락한 거짓된 신의 육체를 파괴해야 한다!","JPN":"必ず地上に墜落した偽りの神を破壊せよ！","ENG":"Destroy the Hollow God's body while it's down!","TWN":"請務必摧毀墜落地面的虛神之軀！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"나도 알고 있다고…! 검은 갑옷……!","JPN":"言われなくてもそうするよ……！　黒い鎧……！","ENG":"Yeah, I know already...! Black armor...!","TWN":"我也知道！黑色盔甲……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"오른쪽 날개는 내가 묶을게. 너는 반대쪽을 날려버려……!!","JPN":"右の翼はあたしが止める。あんたは反対側をぶっ飛ばしな……！！","ENG":"I'll pin down the right wing. You blow off the other side...!!","TWN":"右邊的翅膀由我來綁住。你把另一邊炸飛！？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"다리와 날개가 파괴된 지금이 기회야!","JPN":"足と翼が壊れた今がチャンスだ！","ENG":"Its legs and wings are down. Now's our chance!","TWN":"腿和翅膀被摧毀了，現在是好機會！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"달리라고, 유미나…!! 네 백업은 이쪽에서 맡을 테니까……!!","JPN":"走れ、ミナ……！！　あんたのバックアップはこっちに任せろ……！！","ENG":"Go, Yoo Mina...!! We've got your back from here...!!","TWN":"快跑，劉米娜……！這邊會負責支援你的……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"몸체가 또 재생하기 전에 승부를 봐야 해……!!","JPN":"身体がまた再生する前に、勝負を決めるんだ……！！","ENG":"We must finish this before it regenerates again...!!","TWN":"在他身體再次重生之前，必須分出勝負！？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"고마워, 라이카!","JPN":"ありがとう、ライカ！","ENG":"Thanks, Laika!","TWN":"謝謝你，萊卡！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고……!","JPN":"だったら……！","ENG":"And with this...!","TWN":"還有！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>울브즈베인 – 레거시 모드 기동</color>","JPN":"<color=#ffd34c>ウルブズベイン – レガシーモード起動</color>","ENG":"<color=#ffd34c>Wolvesbane - Legacy Mode activated.</color>","TWN":"<color=#ffd34c>狼之災禍 – 遺留模式啟動</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>전술 업데이트 – 발퀴레 근접 반응형 집속검</color>","JPN":"<color=#ffd34c>戦術アップデート – ワルキューレ近接反応型集束剣</color>","ENG":"<color=#ffd34c>Tactical update - Valkyrie melee response focus blade.</color>","TWN":"<color=#ffd34c>戰術升級 – 女武神近戰反應型聚能劍</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_SKILL_START"},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이걸로 결착을 짓겠어……!!","JPN":"これで決着をつける……！！","ENG":"This ends now...!!","TWN":"就用這個來解決……！"},"stage":{"bg":"BLACK","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"받아라……!!","JPN":"食らえっ……！！","ENG":"Take that...!!","TWN":"接住……！"},"stage":{"bg":"BLACK","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"……이거 믿을 수 없군.","JPN":"……信じられない。","ENG":"...Unbelievable.","TWN":"……這真是難以置信。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"설마, 인간이 데우스 엑스 마키나를 쓰러트릴 줄이야…….","JPN":"まさか、人間の身でデウス・エクス・マキナを倒してしまうとは……","ENG":"I can't believe humans actually brought down a Deus Ex Machina...","TWN":"沒想到，人類竟然能打倒機械神……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"데우스 엑스 마키나라고요……?","JPN":"デウス・エクス・マキナ……？","ENG":"Deus Ex Machina...?","TWN":"機械神？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네, 이 세계를 끝내기 위해 나타난 거짓된 신이라고 할 수 있지.","JPN":"ああ、この世界に終焉をもたらすために現れた、偽りの神さ。","ENG":"Yes. A Hollow God that meant to bring about the end of this world.","TWN":"是的，可以說是為了終結這個世界而出現的虛神。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어쩌면 저 이방인들은 내가 예상했던 것보다 훨씬 더 강할지도 모르겠군.","JPN":"もしかすると、あの異邦人たちは私の予想よりも遥かに強いのかもしれんな。","ENG":"Those outsiders may be far stronger than I expected.","TWN":"也許那些外邦人比我預想的要強得多。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"세계를 끝내기 위해 나타난 신…….","JPN":"世界に終焉をもたらすために現れた神……","ENG":"A god meant to end the world...","TWN":"為了終結世界而出現的神……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면… 그 거짓된 신을 쓰러트렸으니까 이제 모두 끝난 건가요……?","JPN":"でしたら……その偽りの神を倒したから、これで全部終わったのですか……？","ENG":"Then... now that the false god is defeated, is everything over...?","TWN":"那麼……既然那個虛神已經被打倒了，現在一切都結束了嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 그렇지는 않아.","JPN":"いや、そうではない。","ENG":"No. I'm afraid it's not.","TWN":"不，不是這樣的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"한번 깨져버린 컵은 결코 원래대로 돌아오지 않으니까.","JPN":"一度割れてしまったコップは、決して元の形には戻らないのと同じように。","ENG":"Once a cup is broken, it can never be made whole again.","TWN":"破鏡重圓終有隙。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마찬가지로 한 번 임계치에 다다른 세계가 되돌아올 일은 없겠지.","JPN":"一度臨界値に到達した世界が元に戻ることはない。","ENG":"Likewise, a world that has reached its breaking point won't just recover.","TWN":"同樣，一旦達到臨界點的世界就不會再回來了吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇지만…….","JPN":"でも……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 여자, 미래의 저는 세계를 되돌릴 수 있다고 했잖아요.","JPN":"彼女は、未来の私は世界を元に戻せると言いました。","ENG":"That woman, my future self, said we could turn the world back.","TWN":"那個女人，未來的我不是說可以讓世界恢復原樣嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그게 정말로 가능할까요?","JPN":"それは本当に可能なのでしょうか？","ENG":"Is that really possible?","TWN":"那真的可能嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"글쎄, 그건 나 역시도 잘 모르겠군.","JPN":"さあ、それは私にもわからないね。","ENG":"Honestly, I don't know either.","TWN":"這個嘛，我也不太清楚。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 뭐든지 다 아는 줄 알았는데, 당신도 모르는 게 있네요.","JPN":"ふふ、何でも知っていると思っていましたが、あなたにもわからないものはあるんですね。","ENG":"Haha. I thought you knew everything, but even you have limits.","TWN":"呵呵，我以為你什麼都知道，原來你也有不知道的事情啊。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 그야 물론이지 않나?","JPN":"当然のことじゃないか。","ENG":"Haha, of course I do.","TWN":"呵呵，那當然不是嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나라고 어떻게 이 세계의 모든 진실을 알고 있겠어?","JPN":"私とて、この世界の全ての真実を知ることは叶わないよ。","ENG":"There's no way I could know every truth about this world.","TWN":"我怎麼可能知道這個世界的所有真相呢？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만…….","JPN":"しかし……","ENG":"But still...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인……?","JPN":"アバーライン……？","ENG":"Abberline...?","TWN":"艾伯林？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"지금 어디 가는 거예요? 설마, 그쪽은……?","JPN":"どこに行くのですか？　そっちはまさか……？","ENG":"Where are you going? That direction is...?","TWN":"現在要去哪裡？難道，是那邊……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 적어도 마지막에는 나에게 주어진 역할을 다해야겠지.","JPN":"せめて、最後は自分に課せられた役割を果たすべきだろう。","ENG":"At the very least, I need to fulfill the role given to me in the end.","TWN":"但至少在最後，我必須完成賦予我的使命。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"수수께끼 풀이가 내 업일 테니까.","JPN":"謎解きが、私の仕事のはずだから。","ENG":"Solving mysteries is my job, after all.","TWN":"解謎是我的工作。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はぁ、はぁ、はぁ……！","ENG":"*Huff* *Huff* *Huff...!*","TWN":"哈啊，哈啊，哈啊！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"후우우. 역시 도르마 없이 클리포트 인자를 다루는 건, 제법 부담이 가네.","JPN":"ふう、やっぱりドルマなしでクリフォトファクターを扱うのは、なかなか負担が大きいな。","ENG":"Whew... Manipulating the Qliphoth Factor without Droma really takes a toll.","TWN":"呼呼呼。果然沒有多爾瑪來處理神聖因數，還是有些吃力啊。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"기억을 불러오는 건, 앞으로 네다섯 번 정도가 무난하려나.","JPN":"記憶を呼び起こすのは、あと4、5回といったところか。","ENG":"I probably have about four or five memory pulls left in me.","TWN":"喚起記憶的話，大概四、五次左右比較合適吧。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"굉장해…! 정말로 6종 침식체를 쓰러트렸잖아……?","JPN":"すごい……！　本当に第6種侵食体を倒した……！","ENG":"That was amazing...! You really took down a Category 6 C.O...!","TWN":"太厲害了！你真的打敗了6類侵蝕體？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"야, 꼬맹이. 나이스 서포트였다고. 좀 더 자랑스러워해도 돼!","JPN":"おい、おこちゃま。ナイスアシスタントだった。もっと誇らしく思え！","ENG":"Hey, kid. That was some top-notch support. You should be proud!","TWN":"喂，小鬼。是個很好的助攻啊。可以更自豪一點！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어이, 거기 둘! 뭘 다 끝난 것처럼 굴고 있어?","JPN":"そこの二人！　なに全部終わったみたいな雰囲気出してんの！","ENG":"Hey, you two! Why are you acting like it's over?","TWN":"喂，那邊那兩位！你們怎麼一副事情都解決了的樣子？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"긴장을 늦추지 마. 겨우 이 정도로 끝날 리 없으니까.","JPN":"気を緩めなるな。この程度で終わるはずがない。","ENG":"Stay sharp. There's no way it ends this easily.","TWN":"不要放鬆警戒。事情不可能就這樣結束。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"과연… 거짓된 신을 이렇게 쉽게 쓰러트리다니…….","JPN":"ほう。偽りの神をこうも簡単に倒してしまうとは……","ENG":"Impressive... Taking down a false god so easily...","TWN":"果然……竟然這麼輕易地打倒了虛神……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지난 번에 봤을 때보다 확실히 성장했군요, 늑대.","JPN":"以前会った時より確実に成長しましたね、オオカミ。","ENG":"You've definitely grown, Wolf. Much more than last time.","TWN":"比上次見到的時候確實成長了不少啊，狼。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그게 아니라면, 상처를 회복한 만전의 상태라서 그런 걸까요?","JPN":"それとも、傷が治って本調子になったからでしょうか？","ENG":"Or perhaps it's just that you're fully recovered now?","TWN":"如果不是這樣的話，是因為傷口已經痊癒，狀態完好嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"스완……!","JPN":"スワン……！","ENG":"Swan...!","TWN":"史旺！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"자, 보라고! 이 세계의 허신을 쓰러트렸어……!","JPN":"ほら、見なよ！　この世界の虚神は倒した……！","ENG":"Look at that! We took down the Hollow God...!","TWN":"看吧！我們在這個世界打倒了虛神！？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 이상, 네가 뭘 더 꾸미고 있는지는 모르겠지만, 이제 그딴 건 상관없어……!","JPN":"あなたが何を企んでいるのかは知らないけど……もうそんなこと、どうでもいい！","ENG":"I don't know what else you've got planned, but none of it matters anymore...!","TWN":"我不知道你還在打什麼主意，但現在那些都無所謂了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 얌전히 포기하고 노엘을 넘겨……!","JPN":"だから大人しく諦めて、ノエルを返して……！","ENG":"So just give up and hand over Noelle...!","TWN":"所以乖乖放棄，把洛艾兒交出來！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"노엘……?","JPN":"ノエル……？","ENG":"Noelle...?","TWN":"洛艾兒？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"잠깐, 그 이름은……?","JPN":"その名前は……？","ENG":"Wait, that name...","TWN":"等等，那名字是？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"잠깐만요, 미나 씨!","JPN":"待ってください、ミナさん！","ENG":"Hold on, Mina!","TWN":"等一下，米娜！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"지금 스완 옆에 있는 저 아이가 노엘이라고요……?","JPN":"今スワンの隣にいるあの子が、ノエルだと言うのですか……？","ENG":"You're saying that girl next to Swan is Noelle...?","TWN":"現在在史旺旁邊的那個孩子就是洛艾兒嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"정말 노엘이 맞아요?","JPN":"本当にノエルですか？","ENG":"Are you sure it's really her?","TWN":"真的是洛艾兒嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 갑자기 뜬금없이 그게 무슨 소리야……?","JPN":"は？　いきなり何を言うの……？","ENG":"What? What are you suddenly saying...?","TWN":"什麼？你突然說這種話?"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당연히 누가 봐도 쟤가……","JPN":"どこからどう見てもあの子が……","ENG":"Isn't it obvious that she's–","TWN":"當然，誰看了都會覺得那傢伙……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐?","JPN":"いや、待って？","ENG":"Hold on.","TWN":"等一下？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 미나 양…….","JPN":"そして、ミナさん……","ENG":"And Mina...","TWN":"還有米娜……"},"stage":{"bg":"OFFICE_TOP","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신은 지금 <color=#ffd34c>정보 말소</color>의 후유증을 겪는 거예요.","JPN":"あなたは今、<color=#ffd34c>情報抹消</color>の後遺症を患っています。","ENG":"You're experiencing the aftereffects of <color=#ffd34c>information erasure</color>.","TWN":"你現在正在經歷<color=#ffd34c>資訊抹消</color>的後遺症。"},"stage":{"bg":"OFFICE_TOP","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트! 그럼, 너 설마……?","JPN":"フェリセット！　じゃあ、あなたまさか……？","ENG":"Félicette! But it can't be...","TWN":"費莉塞特！那麼，你該不會是……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이건…? 갑자기 연쇄 차원 균열이라고……?","JPN":"これは……？　次元の亀裂が、相次いで……？","ENG":"What...? Sudden chain dimensional rifts...?","TWN":"這是……突然說是連鎖次元裂縫？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"허신을 쓰러트렸을 텐데…? 어째서……?","JPN":"虚神は倒したはずなのに……？　どうして……？","ENG":"We took down the Hollow God... So why...?","TWN":"明明打倒了虛神？怎麼可能？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐야, 유미나. 설마 너도 이게 끝이라고 생각한 거야?","JPN":"何だよ、ミナ？　あんたもまさかこれで終わりだと思ってたわけ？","ENG":"Seriously, Yoo Mina. Don't tell me you thought that was the end?","TWN":"什麼？劉米娜。難道你也認為這就是結束了嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"え……？","ENG":"What...?","TWN":"你說什麼？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"역시 리트리버답게 제법 냄새를 잘 맡는군요.","JPN":"やはりレトリーバーだけに、匂いに敏感ですね。","ENG":"You do have a sharp nose like a real retriever.","TWN":"果然不愧是獵犬，嗅覺真靈敏啊。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제6종 침식체, 허신의 특징 중 하나는 연쇄적인 차원 균열을 발생시킨다는 점이죠.","JPN":"第6種侵食体、虚神の特徴の一つは、連鎖的な次元の亀裂を発生させること。","ENG":"One of the defining traits of the Category 6 C.O. Hollow God is its ability to trigger chain dimensional rifts.","TWN":"6類侵蝕體，虛神的特點之一就是能夠引發連鎖的次元裂縫。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"대처가 조금이라도 늦어지면, 허수 차원을 떠돌던 다른 6종 침식체를 끌어들이게 된답니다.","JPN":"少しでも対応が遅れれば、虚数次元を漂っていた他の第6種侵食体を引き込んでしまいます。","ENG":"If you don't respond quickly enough, it'll start pulling in other Category 6 C.O.s drifting through the imaginary dimension.","TWN":"如果應對稍有遲緩，就會引來在虛空次元中遊蕩的其他6類侵蝕體。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"잠깐…! 망원경이 신성을 관측하고 있어요……!","JPN":"なっ……！　望遠鏡が神聖を観測しています……！","ENG":"Wait...! The Telescope's picking up the Divinity signals...!","TWN":"等一下！？遠鏡正在觀測神聖！？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"하나… 둘… 셋……? 반응 다수……!","JPN":"いち……に……さん……？　反応多数……！","ENG":"One... two... three...?! Multiple readings...!","TWN":"一……二……三？多處反應……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"서, 설마 이게 전부……?","JPN":"ま、まさかこれが全部……？","ENG":"N-no way, all of these...?!","TWN":"難、難道這些都是？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"제기랄, 이거 야단났네.","JPN":"ちくしょう、これはやばいな。","ENG":"Dammit, this isn't looking good.","TWN":"可惡，這下糟了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그거 하나 잡는 것도 이 개고생을 했는데……!","JPN":"あれ一体でもかなり苦労したっていうのに……！","ENG":"We nearly died just taking down one...!","TWN":"抓住一個都這麼費勁！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇게 끌어들여진 6종 침식체는 또다시 다른 6종 침식체를 끌어들이게 되고…….","JPN":"そうして引き込まれた第6種侵食体は、また違う第6種侵食体を引き込み……","ENG":"Each Category 6 C.O. that's drawn in will summon another Category 6 C.O...","TWN":"這樣被吸引來的6類侵蝕體又會再次吸引其他6類侵蝕體……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결과적으로 세계는 다수의 6종 침식체가 방출하는 침식파를 견디지 못하고 붕괴하죠.","JPN":"結果として世界は複数の第6種侵食体が放つ侵食波に耐えられず、崩壊するでしょう。","ENG":"Eventually, the world collapses under the pressure of the Corruption rays emitted by them.","TWN":"最好世界會因無法承受多個6類侵蝕體釋放的侵蝕波，最終崩潰。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아이러니 하게도, 이것은 세계가 스스로를 수호하기 위한 마지막 방어기제인 동시에…….","JPN":"皮肉なことに、これは世界が自らを守るための最後の防衛機制であると同時に……","ENG":"Ironically, this is both the world's final defense mechanism...","TWN":"諷刺的是，這既是世界自我保護的最後防禦機制，同時也是……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"보통의 세계들이 멸망에 이르는 수순이라고 할 수 있답니다.","JPN":"一般的な世界が滅亡に至る手順とも言えます。","ENG":"And at the same time, it's the very process by which most worlds meet their end.","TWN":"普通世界走向滅亡的步驟。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 우리 세계 또한 마찬가지였죠.","JPN":"そして私の世界も、例外ではありませんでした。","ENG":"Ours was no different.","TWN":"我們的世界也是一樣。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"자아, 모든 것은 각본대로.","JPN":"さあ、すべては脚本どおりに。","ENG":"Now then, everything according to the script.","TWN":"那麼，一切都將按照劇本進行。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"각본가로서 제법 기대가 되는 순간이로군요.","JPN":"脚本家として、なかなか期待が高まる瞬間ですね。","ENG":"As a scriptwriter, I must say this is quite the exciting moment.","TWN":"作為編劇，這一刻讓我充滿期待。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"과연 당신들은 엔딩이 확정된 이 각본을 뒤집을 수 있을까요?","JPN":"果たしてあなたたちは、このエンディングの確定した脚本を覆せるのでしょうか。","ENG":"Let's see if you can overturn a script that already has its ending written.","TWN":"你們真的能顛覆這個已經確定結局的劇本嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"스완……!","JPN":"スワン……！","ENG":"Swan...!","TWN":"史旺！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};